//! CLI that reads `docs/conformance.json` and updates the autogenerated
//! section of `docs/conformance.md`.

use std::path::PathBuf;

use anyhow::Context;
use clap::Parser;

use rcc_conformance::render::{render_dashboard, splice_autogen};
use rcc_conformance::Report;

/// Render the conformance dashboard from JSON into Markdown.
#[derive(Parser)]
#[command(name = "rcc_conformance_render")]
struct Cli {
    /// Path to the JSON report (default: `docs/conformance.json`).
    #[arg(long, default_value = "docs/conformance.json")]
    input: PathBuf,

    /// Path to the Markdown dashboard (default: `docs/conformance.md`).
    #[arg(long, default_value = "docs/conformance.md")]
    output: PathBuf,
}

fn main() -> anyhow::Result<()> {
    let cli = Cli::parse();

    let json = std::fs::read_to_string(&cli.input)
        .with_context(|| format!("reading {}", cli.input.display()))?;
    let report: Report = serde_json::from_str(&json).with_context(|| "parsing conformance JSON")?;

    let table = render_dashboard(&report);

    let md = std::fs::read_to_string(&cli.output)
        .with_context(|| format!("reading {}", cli.output.display()))?;

    let updated = splice_autogen(&md, &table)?;

    std::fs::write(&cli.output, &updated)
        .with_context(|| format!("writing {}", cli.output.display()))?;

    let total_suites = report.suites.len();
    eprintln!("updated {} ({total_suites} suites)", cli.output.display());

    Ok(())
}
